class Solution:
    def closestRoom(self, rooms, queries):
        ans = []
        for pref, msz in queries:
            best_id = -1
            best_dist = None
            for rid, sz in rooms:
                if sz >= msz:
                    d = abs(rid - pref)
                    if best_dist is None or d < best_dist or (d == best_dist and rid < best_id):
                        best_dist = d
                        best_id = rid
            ans.append(best_id)
        return ans

