var closestRoom = function(rooms, queries) {
    rooms = rooms.slice().sort((a, b) => a[1] - b[1]);
    const order = queries.map((_, i) => i).sort((a, b) => queries[a][1] - queries[b][1]);
    const ans = new Array(queries.length).fill(-1);
    const ids = [];
    const insort = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const m = (lo + hi) >> 1; if (arr[m] < x) lo = m + 1; else hi = m; }
        arr.splice(lo, 0, x);
    };
    const bisectLeft = (arr, x) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const m = (lo + hi) >> 1; if (arr[m] < x) lo = m + 1; else hi = m; }
        return lo;
    };
    let idx = rooms.length - 1;
    for (let oi = order.length - 1; oi >= 0; oi--) {
        const qi = order[oi];
        const pref = queries[qi][0], msz = queries[qi][1];
        while (idx >= 0 && rooms[idx][1] >= msz) { insort(ids, rooms[idx][0]); idx--; }
        if (ids.length === 0) { ans[qi] = -1; continue; }
        const pos = bisectLeft(ids, pref);
        let best = -1, bestDist = null;
        for (const p of [pos - 1, pos]) {
            if (p >= 0 && p < ids.length) {
                const rid = ids[p];
                const d = Math.abs(rid - pref);
                if (bestDist === null || d < bestDist || (d === bestDist && rid < best)) { bestDist = d; best = rid; }
            }
        }
        ans[qi] = best;
    }
    return ans;
};
